function solve(n, edges) {
    // DSU structure initialization
    const parent = Array(n).fill(0).map((_, i) => i);
    // parity[i] stores the parity of the path weight from node i to its parent
    const parity = Array(n).fill(0);
    let edgeCount = 0;

    /**
     * Finds the root of node i and performs path compression.
     * Returns [root, parity_to_root].
     * parity_to_root is the parity of the path weight from i to root.
     */
    function find(i) {
        if (parent[i] === i) {
            return [i, 0];
        }

        // Recursively find the root and the distance from parent[i] to the root
        const [root, dist_parent_to_root] = find(parent[i]);

        // Path compression: Update parent[i] to point directly to the root
        parent[i] = root;

        // Update parity[i]: new_parity = (original_parity_i_to_parent) XOR (parity_parent_to_root)
        parity[i] = parity[i] ^ dist_parent_to_root;

        return [root, parity[i]];
    }

    for (const edge of edges) {
        const u = edge[0];
        const v = edge[1];
        const w = edge[2]; // w is 0 or 1

        // 1. Find roots and path parities
        const [rootU, distU] = find(u); // distU: parity u -> rootU
        const [rootV, distV] = find(v); // distV: parity v -> rootV

        if (rootU !== rootV) {
            // Case 1: Different components. We add the edge and union the components.
            edgeCount++;

            // Union by rank/size is usually better, but for simplicity and complexity guarantee,
            // we merge V's component into U's component.
            parent[rootV] = rootU;

            // Calculate the required parity for the new edge (rootV -> rootU).
            // Path: rootV -> v (distV) -> u (w) -> rootU (distU)
            // Parity(rootV -> rootU) = Parity(rootV -> v) XOR w XOR Parity(u -> rootU)
            // Note: Parity(rootV -> v) = distV
            const parityRootVToRootU = distV ^ w ^ distU;
            parity[rootV] = parityRootVToRootU;

        } else {
            // Case 2: Same component. Check cycle parity.
            // A cycle is formed by (u -> rootU) -> (v -> rootU) + edge (v, u).
            // Cycle Parity = distU XOR w XOR distV

            const cycleParity = distU ^ w ^ distV;

            // If cycleParity is 0 (even), we add the edge.
            if (cycleParity === 0) {
                edgeCount++;
            }
            // If cycleParity is 1 (odd), we reject the edge.
        }
    }

    return edgeCount;
}

